      checkValidFloatingPoint(doubleValue);
    }
    out.value(doubleValue);
  }
}

private static void checkValidFloatingPoint(double value) {
  if (Double.isNaN(value) || Double.isInfinite(value)) {
    throw new IllegalArgumentException(
