          T map = (T) new EnumMap((Class) elementType);
          return map;
        } else {
          throw new JsonIOException("Invalid EnumMap type: " + type);
        }
      } else {
        throw new JsonIOException("Invalid EnumMap type: " + type);
      }
    };
  }

  return null;
}

